&lt;/ul&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mtable rowspacing=&#34;0.24999999999999992em&#34; columnalign=&#34;right left&#34; columnspacing=&#34;0em&#34;&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mo&gt;⪯&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mtext&gt;  &lt;/mtext&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mtext&gt;  &lt;/mtext&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;v&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\begin{aligned}&amp;amp; (A,\preceq)\ \ or\ \ abbreviated\ as\ A 
\end{aligned}
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.5000000000000002em;vertical-align:-0.5000000000000002em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mtable&#34;&gt;&lt;span class=&#34;col-align-r&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1em;&#34;&gt;&lt;span style=&#34;top:-3em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.84em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.5000000000000002em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;col-align-l&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1em;&#34;&gt;&lt;span style=&#34;top:-3.16em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;⪯&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;v&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.5000000000000002em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;h1 id=&#34;全序&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#全序&#34;&gt;#&lt;/a&gt; 全序&lt;/h1&gt;
&lt;p&gt;or&lt;br /&gt;
 线序&lt;/p&gt;
&lt;h2 id=&#34;定义-14&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#定义-14&#34;&gt;#&lt;/a&gt; 定义&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mtable rowspacing=&#34;0.24999999999999992em&#34; columnalign=&#34;right left&#34; columnspacing=&#34;0em&#34;&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mtext&gt;偏序集&lt;/mtext&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mtext&gt;的任意两个元素都可比，则这个偏序集是全序或线序&lt;/mtext&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\begin{aligned}&amp;amp; 偏序集A的任意两个元素都可比，则这个偏序集是全序或线序
\end{aligned}
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.5000000000000002em;vertical-align:-0.5000000000000002em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mtable&#34;&gt;&lt;span class=&#34;col-align-r&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1em;&#34;&gt;&lt;span style=&#34;top:-3em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.84em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.5000000000000002em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;col-align-l&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1em;&#34;&gt;&lt;span style=&#34;top:-3.16em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;偏&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;序&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;集&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;的&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;任&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;意&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;两&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;个&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;元&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;素&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;都&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;可&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;比&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;，&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;则&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;这&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;个&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;偏&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;序&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;集&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;是&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;全&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;序&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;或&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;线&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;序&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.5000000000000002em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;h1 id=&#34;关系举例-幂集上的&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关系举例-幂集上的&#34;&gt;#&lt;/a&gt; 关系举例 - 幂集上的:&lt;/h1&gt;
&lt;h2 id=&#34;真包含关系&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#真包含关系&#34;&gt;#&lt;/a&gt; 真包含关系&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;反自反、反对称、传递&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;恒等关系-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#恒等关系-2&#34;&gt;#&lt;/a&gt; 恒等关系&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;自反、对称、反对称、传递&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;全关系-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#全关系-2&#34;&gt;#&lt;/a&gt; 全关系&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;自反、对称、传递&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;空关系-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#空关系-2&#34;&gt;#&lt;/a&gt; 空关系&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;反自反、对称、反对称、传递&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;思维导图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#思维导图&#34;&gt;#&lt;/a&gt; 思维导图&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/principles-of-computer-composition/DRAM%E5%88%B7%E6%96%B0.png&#34; alt=&#34;DRAM刷新&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;为什么要刷新&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#为什么要刷新&#34;&gt;#&lt;/a&gt; 为什么要刷新？&lt;/h1&gt;
&lt;h2 id=&#34;dram存储位元的特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dram存储位元的特点&#34;&gt;#&lt;/a&gt; DRAM 存储位元的特点&lt;/h2&gt;
&lt;h2 id=&#34;靠电容上的电荷存储效应记忆信息虽然有mos高电阻1012-sim-1015-omega仍会泄漏电荷&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#靠电容上的电荷存储效应记忆信息虽然有mos高电阻1012-sim-1015-omega仍会泄漏电荷&#34;&gt;#&lt;/a&gt; 靠电容上的电荷存储效应记忆信息，虽然有 MOS 高电阻 (&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;msup&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;mn&gt;12&lt;/mn&gt;&lt;/msup&gt;&lt;mo&gt;∼&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;msup&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;mn&gt;15&lt;/mn&gt;&lt;/msup&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;Ω&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;10^{12} \sim 10^{15} \Omega&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8141079999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;∼&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8141079999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;5&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;Ω&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;)，仍会泄漏电荷&lt;/h2&gt;
&lt;h2 id=&#34;为保证所存信息的正确性需要用充电的方法及时使所有位元的电容上电荷恢复到泄漏前的状态&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#为保证所存信息的正确性需要用充电的方法及时使所有位元的电容上电荷恢复到泄漏前的状态&#34;&gt;#&lt;/a&gt; 为保证所存信息的正确性，需要用充电的方法及时使所有位元的电容上电荷恢复到泄漏前的状态&lt;/h2&gt;
&lt;h1 id=&#34;dram刷新的有关参数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dram刷新的有关参数&#34;&gt;#&lt;/a&gt; DRAM 刷新的有关参数&lt;/h1&gt;
&lt;h2 id=&#34;刷新周期-trc-refresh-cycle&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#刷新周期-trc-refresh-cycle&#34;&gt;#&lt;/a&gt; 刷新周期 Trc (refresh cycle)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;对同一存储位元连续两次刷新，仍能保证鉴别出原存信息的最大允许间隔时间，即在 Trc 内必须对每个单元刷新一遍&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;一般为 ms 级，亦称为刷新间隔时间&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;在 Trc 时间内，应刷新存储芯片中的所有存储位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;在 DRAM 芯片的主要性能参数中，都给出 Trc。通常为 2ms、4ms、8ms&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Trc &amp;lt; Tref&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;刷新操作周期-troc-refresh-operating-cycle&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#刷新操作周期-troc-refresh-operating-cycle&#34;&gt;#&lt;/a&gt; 刷新操作周期 Troc (refresh operating cycle)&lt;/h2&gt;
&lt;p&gt;刷新一行存储位元所需时间，通常和 DRAM 读写周期 tRC /tWC 相同&lt;/p&gt;
&lt;h2 id=&#34;刷新操作周期数-nr-number-of-refresh-operating-cycle&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#刷新操作周期数-nr-number-of-refresh-operating-cycle&#34;&gt;#&lt;/a&gt; 刷新操作周期数 Nr (Number of refresh operating cycle)&lt;/h2&gt;
&lt;p&gt;存储芯片所有位元刷新一遍所需的刷新操作周期个数。它与芯片的内部结构有关。&lt;br /&gt;
即每次可以刷新一行， Nr 决定于存储矩阵的行数&lt;/p&gt;
&lt;h2 id=&#34;信息保持时间-tref-不太重要&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#信息保持时间-tref-不太重要&#34;&gt;#&lt;/a&gt; 信息保持时间 Tref (不太重要)&lt;/h2&gt;
&lt;p&gt;从信息以电荷形式存入电容，到电荷经过一段时间泄漏，读放仍能鉴别出原存信息的时间&lt;/p&gt;
&lt;h1 id=&#34;按刷新操作周期的分配方式分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按刷新操作周期的分配方式分类&#34;&gt;#&lt;/a&gt; 按刷新操作周期的分配方式分类&lt;/h1&gt;
&lt;h2 id=&#34;集中式刷新&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#集中式刷新&#34;&gt;#&lt;/a&gt; 集中式刷新&lt;/h2&gt;
&lt;p&gt;也叫 “批刷新”，从刷新周期 Trc 中抽出连续一段长度的访存周期作为刷新操作周期集中进行刷新&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;缺点：集中式刷新使 98.976% 的时间用于访存，这期间存储器的效能得以充分发挥，但有 1.024% 的时间，即在 8ms 中有 81.92μs 不允许访存，CPU 要处于等待状态，影响了计算机的工作效率&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;优点：控制逻辑简单，设计容易实现&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;分散式刷新&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分散式刷新&#34;&gt;#&lt;/a&gt; 分散式刷新&lt;/h2&gt;
&lt;p&gt;把集中到一起的不允许访存的刷新时间分散开，每个等分的最后一个访存周期用作刷新操作周期，以完成一行存储位元的刷新，其余时间则用于访存&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;优点：降低了访存的阻塞时间，提高了计算机的工作效率&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;缺点：控制逻辑复杂，设计不易实现&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;透明式刷新&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#透明式刷新&#34;&gt;#&lt;/a&gt; 透明式刷新&lt;/h2&gt;
&lt;p&gt;设一个系统的访存周期是存储器实际访存周期的两倍，并令系统访存周期的前半周期用于访存，后半周期用于刷新&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;优点：控制简单、设计容易，不需增加多少器件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;缺点：存储器的效能仅利用 50％，仅用于低速系统&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;思维导图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#思维导图&#34;&gt;#&lt;/a&gt; 思维导图&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/principles-of-computer-composition/%E8%99%9A%E6%8B%9F%E5%AD%98%E5%82%A8%E5%99%A8.png&#34; alt=&#34;虚拟存储器&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;分区方案&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分区方案&#34;&gt;#&lt;/a&gt; 分区方案&lt;/h1&gt;
&lt;h2 id=&#34;简单分区&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#简单分区&#34;&gt;#&lt;/a&gt; 简单分区：&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;原理：使用长度不等的固定长分区，当一个进程调入主存时，分配给它一个能容纳的最小分区&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;缺点：固定长度的分区，可能会浪费 主存空间。多数情况下，进程对分区大小的需求不可能和提供的分区大小一样&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;可变长分区partitioning&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#可变长分区partitioning&#34;&gt;#&lt;/a&gt; 可变长分区（Partitioning）&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;原理：分配的分区大小与进程所需大小一样&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;特点：开始较好 ，但到最后存储器中会有许多碎片。时间越长，存储器的碎片会越来越多，存储器的利用率下降&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;程序员自己手动管理内存，可以改善内存碎片化问题（例如一次性 malloc 或 new、stl 新建容器好几 kb 大小……&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;分页paging&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分页paging&#34;&gt;#&lt;/a&gt; 分页（Paging）&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;基本思想&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;内存分成固定长且较小的存储块 (页框 /page frame)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;每个进程也划分成固定长的程序块 (页 /page)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;程序块 (页 /page) 可装到内存可用的存储块 (页框 /page frame) 中&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;无需用连续页框来存放一个进程&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;操作系统为每个进程生成一个页表：页和页框一一对应的关系表&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;通过页表 (page table) 实现逻辑地址向物理地址转换 (Address Mapping)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;虚存技术的实质&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#虚存技术的实质&#34;&gt;#&lt;/a&gt; 虚存技术的实质&lt;/h1&gt;
&lt;h2 id=&#34;程序员在比实际主存空间大得多的逻辑地址空间编写程序&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#程序员在比实际主存空间大得多的逻辑地址空间编写程序&#34;&gt;#&lt;/a&gt; 程序员在比实际主存空间大得多的逻辑地址空间编写程序&lt;/h2&gt;
&lt;h2 id=&#34;程序执行时把当前需要的程序段和相应的数据块调入主存其他暂不用的部分存放在磁盘上&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#程序执行时把当前需要的程序段和相应的数据块调入主存其他暂不用的部分存放在磁盘上&#34;&gt;#&lt;/a&gt; 程序执行时，把当前需要的程序段和相应的数据块调入主存，其他暂不用的部分存放在磁盘上&lt;/h2&gt;
&lt;h2 id=&#34;指令执行时通过硬件将逻辑地址亦称虚拟地址或虚地址转化为物理地址亦称主存地址或实地址分页查表&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#指令执行时通过硬件将逻辑地址亦称虚拟地址或虚地址转化为物理地址亦称主存地址或实地址分页查表&#34;&gt;#&lt;/a&gt; 指令执行时，通过硬件将逻辑地址 (亦称虚拟地址或虚地址) 转化为物理地址 (亦称主存地址或实地址)// 分页查表&lt;/h2&gt;
&lt;h2 id=&#34;在发生指令或数据访问失效时由操作系统进行主存和磁盘之间的信息交换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在发生指令或数据访问失效时由操作系统进行主存和磁盘之间的信息交换&#34;&gt;#&lt;/a&gt; 在发生指令或数据访问失效时，由操作系统进行主存和磁盘之间的信息交换&lt;/h2&gt;
&lt;h2 id=&#34;每个进程都有专属于自己的从0到ffffffffh的地址空间&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#每个进程都有专属于自己的从0到ffffffffh的地址空间&#34;&gt;#&lt;/a&gt; 每个进程都有专属于自己的从 0 到 FFFFFFFFH 的地址空间&lt;/h2&gt;
&lt;h1 id=&#34;快表-转换后备缓冲器-tlb-translation-lookaside-buffer&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#快表-转换后备缓冲器-tlb-translation-lookaside-buffer&#34;&gt;#&lt;/a&gt; 快表 / 转换后备缓冲器 / TLB (Translation Lookaside Buffer)&lt;/h1&gt;
&lt;h2 id=&#34;原理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#原理&#34;&gt;#&lt;/a&gt; 原理：&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;使用 Cache 来存储页表项，称为 TLB，它包含最近使用的那些页表项，加速虚实地址转换&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;多用全相联：命中率高，小、成本不高&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;采用随机替换策略：降低替换算法开销&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;采用回写策略：减少访问内存的次数&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;tlb页表项&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tlb页表项&#34;&gt;#&lt;/a&gt; TLB 页表项&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Tag 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Index 位，组相联时才有&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Physical Adress，对应物理页框号&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;其他标志位&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Valid 位，1 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Dirty 位，1 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Ref&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Access&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;tlb缺失&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tlb缺失&#34;&gt;#&lt;/a&gt; TLB 缺失&lt;/h2&gt;
&lt;h1 id=&#34;基本概念&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基本概念&#34;&gt;#&lt;/a&gt; 基本概念&lt;/h1&gt;
&lt;h2 id=&#34;主存分配&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主存分配&#34;&gt;#&lt;/a&gt; 主存分配&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;操作系统：固定（ROM）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用户区：分区（RAM）&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;三种地址空间&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三种地址空间&#34;&gt;#&lt;/a&gt; 三种地址空间：&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;虚拟地址空间&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;主存地址空间&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;辅存地址空间&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;地址映射把虚拟地址空间映射到主存地址空间&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#地址映射把虚拟地址空间映射到主存地址空间&#34;&gt;#&lt;/a&gt; 地址映射：把虚拟地址空间映射到主存地址空间&lt;/h2&gt;
&lt;h2 id=&#34;地址变换程序运行时把虚拟地址变换成主存物理地址&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#地址变换程序运行时把虚拟地址变换成主存物理地址&#34;&gt;#&lt;/a&gt; 地址变换：程序运行时，把虚拟地址变换成主存物理地址&lt;/h2&gt;
&lt;h1 id=&#34;为什么需要虚存&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#为什么需要虚存&#34;&gt;#&lt;/a&gt; 为什么需要虚存&lt;/h1&gt;
&lt;h2 id=&#34;同时运行更多进程内存需求增大&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#同时运行更多进程内存需求增大&#34;&gt;#&lt;/a&gt; 同时运行更多进程，内存需求增大&lt;/h2&gt;
&lt;h2 id=&#34;允许多个程序有效而安全地共享存储器消除内存因小而有限的存储器容量给程序设计造成的障碍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#允许多个程序有效而安全地共享存储器消除内存因小而有限的存储器容量给程序设计造成的障碍&#34;&gt;#&lt;/a&gt; 允许多个程序有效而安全地共享存储器，消除内存因小而有限的存储器容量给程序设计造成的障碍&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;可以更有效的共享处理器和主存&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;虚拟存储器实现程序地址空间到物理空间的转换，加强了各个程序地址空间之间的保护&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;允许单用户程序大小超过主存储器的容量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#允许单用户程序大小超过主存储器的容量&#34;&gt;#&lt;/a&gt; 允许单用户程序大小超过主存储器的容量&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;虚拟存储器自动管理主存和辅存组成的两级层次结构&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;虚存组织方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#虚存组织方式&#34;&gt;#&lt;/a&gt; 虚存组织方式&lt;/h1&gt;
&lt;h2 id=&#34;页式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#页式&#34;&gt;#&lt;/a&gt; 页式&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;原理：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;虚存地址空间和主存地址空间按统一大小分成若干页，虚存称为虚页，主存称为实页&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;程序按页从磁盘调入主存 (某一虚页调入某一实页)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;指令给出虚拟地址 / 逻辑地址&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;每个页表项记录对应的虚页情况&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Valid 为 0 说明 “miss”(称为 page fault / 缺页)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 执行指令时，先将逻辑地址转换为物理地址&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;地址转换由 MMU 实现&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;页大小比 Cache 中 Block 大得多&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;采用全相联映射&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通过软件来处理 “缺页”&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;采用 Write Back 写策略&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;地址格式&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;虚存的地址格式 (逻辑地址格式)：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;直接映射虚拟地址&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;高位，虚拟地址比物理地址长的位数，算在 Tag 位里&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Tag 位，标记位&lt;br /&gt;
长度 = log _2 (主存中 页 的 数量 / TLB 中 页表项 的 数量)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Index 位，Cache 槽号&lt;br /&gt;
长度 = log _2 (TLB 中 页表项 的 数量)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Offset 位，页内地址&lt;br /&gt;
长度 = log _2 (页 的 大小) (按编址单位算)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;全相联虚拟地址&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;高位，虚拟地址比物理地址长的位数，算在 Tag 位里&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Tag 位，标记位&lt;br /&gt;
长度 = log _2 (主存中 页 的 数量)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Offset 位，页内地址&lt;br /&gt;
长度 = log _2 (页 的 大小) (按编址单位算)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;n 路组相联虚拟地址&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;高位，虚拟地址比物理地址长的位数，算在 Tag 位里&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Tag 位，标记位&lt;br /&gt;
长度 = log _2 (主存中 页 的 数量 / 组的数量)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;组号位&lt;br /&gt;
长度 = log _2 (组 的 数量)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Offset 位，页内地址&lt;br /&gt;
长度 = log _2 (页 的 大小) (按编址单位算)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;主存的地址格式 (物理地址格式)：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;实页号 / 物理页号&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;页内地址&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;页表 (Page Table)&lt;br /&gt;
 建立一个映射关系表来存放虚拟地址与物理地址之间的映射关系，该映射关系表被称为页表，用来实现虚实地址的转换&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;建立在主存中，操作系统为每道程序建立一个页表&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;设置页表基址寄存器：保存页表在主存中的起始地址&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;页表项&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;装入位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;修改 (Dirty) 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;替换控制位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;访问权限位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;禁止缓存位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;实页号&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;页表的项数 = 页表的容量 = 最大页表项 = 虚存大小 / 页大小&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;页表大小 = 页表的项数 * 页表项大小&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;异常情况&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;缺页 (page fault)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;产生条件：当 Valid (有效位 / 装入位) 为 0 时&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;相应处理：从磁盘中读信息到内存，若内存没有空间，则还要从内存选择一页替换到磁盘上，替换算法类似于 Cache，采用回写法，页面淘汰时，根据 “dirty” 位确定是否要写磁盘&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;异常处理结束后：缺页发生时，当前指令的执行被阻塞，当前进程挂起；缺页处理结束后，回到原指令继续执行&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;保护违例 (protection_violation_fault)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;产生条件： 当 Access Rights (存取权限) 与所指定的具体操作不相符时&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;相应处理：在屏幕上显示 “内存保护错” 信息&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;异常处理结束后：当前指令执行被阻塞，当前进程终止&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Access Rights (存取权限) 可能的取值有哪些？&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;R = Read-only&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;R/W = read/write&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;X = execute only&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;优点：实现简单，开销少。因为只有进程的最后一个零头（内部碎片）不能利用，故浪费很小&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;缺点：由于页不是逻辑上独立的实体，可能会出现如 “一条指令跨页” 等情况（CISC），使处理、管理、保护和共享都不方便&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;段式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#段式&#34;&gt;#&lt;/a&gt; 段式&lt;/h2&gt;
&lt;h2 id=&#34;段页式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#段页式&#34;&gt;#&lt;/a&gt; 段页式&lt;/h2&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;思维导图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#思维导图&#34;&gt;#&lt;/a&gt; 思维导图&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/principles-of-computer-composition/%E5%AD%98%E5%82%A8%E5%99%A8.png&#34; alt=&#34;存储器&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;基本术语&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基本术语&#34;&gt;#&lt;/a&gt; 基本术语&lt;/h1&gt;
&lt;h2 id=&#34;记忆单元-存储位元-位元cell&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#记忆单元-存储位元-位元cell&#34;&gt;#&lt;/a&gt; 记忆单元 / 存储位元 / 位元 (Cell)&lt;/h2&gt;
&lt;p&gt;具有两种稳态的能够表示二进制数 0 和 1 的物理器件&lt;/p&gt;
&lt;h2 id=&#34;存储单元-编址单位-寻址单位addressing-unit&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储单元-编址单位-寻址单位addressing-unit&#34;&gt;#&lt;/a&gt; 存储单元 / 编址单位 / 寻址单位 (Addressing Unit)&lt;/h2&gt;
&lt;p&gt;存储器中具有相同地址的那些位构成一个存储单元，又称为一个编址单位&lt;/p&gt;
&lt;h2 id=&#34;存储体-存储矩阵-存储阵列bank&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储体-存储矩阵-存储阵列bank&#34;&gt;#&lt;/a&gt; 存储体 / 存储矩阵 / 存储阵列 (Bank)&lt;/h2&gt;
&lt;p&gt;所有存储单元构成一个存储阵列&lt;/p&gt;
&lt;h2 id=&#34;存储器地址寄存器memory-address-register-mar&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储器地址寄存器memory-address-register-mar&#34;&gt;#&lt;/a&gt; 存储器地址寄存器 (Memory Address Register – MAR)&lt;/h2&gt;
&lt;p&gt;用于存放主存单元地址的寄存器&lt;/p&gt;
&lt;h2 id=&#34;存储器数据寄存器memory-data-register-mdr&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储器数据寄存器memory-data-register-mdr&#34;&gt;#&lt;/a&gt; 存储器数据寄存器 (Memory Data Register – MDR)&lt;/h2&gt;
&lt;p&gt;用于存放主存单元中数据的寄存器&lt;/p&gt;
&lt;h2 id=&#34;机器字长&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#机器字长&#34;&gt;#&lt;/a&gt; 机器字长&lt;/h2&gt;
&lt;p&gt;运算器中参加运算的寄存器的位数，即：数据通路的宽度&lt;/p&gt;
&lt;h2 id=&#34;存储字&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储字&#34;&gt;#&lt;/a&gt; 存储字&lt;/h2&gt;
&lt;p&gt;存储芯片中一个读写单位，一般等于存储器的数据线宽度&lt;br /&gt;
 32bit 系统是 32 位，64 位系统是 64 位……&lt;/p&gt;
&lt;h2 id=&#34;编址方式addressing-mode对存储体中各存储单元进行编号的方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编址方式addressing-mode对存储体中各存储单元进行编号的方法&#34;&gt;#&lt;/a&gt; 编址方式 (Addressing Mode)：对存储体中各存储单元进行编号的方法&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;按字节编址 (现代计算机基本上都按字节编址)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;按字编址 (早期有机器按字编址)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;传输单位一次读写存储器的数据单位&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#传输单位一次读写存储器的数据单位&#34;&gt;#&lt;/a&gt; 传输单位：一次读写存储器的数据单位&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;对主存而言，指一次从主存读出或写入的数据位数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对辅存而言，数据通常按块传输，传输单位为块&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;计算机存储层次结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算机存储层次结构&#34;&gt;#&lt;/a&gt; 计算机存储层次结构&lt;/h1&gt;
&lt;h2 id=&#34;&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#&#34;&gt;#&lt;/a&gt; &lt;/h2&gt;
&lt;h2 id=&#34;从上到下一级一级查找找到后再从下往上一级一级存&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#从上到下一级一级查找找到后再从下往上一级一级存&#34;&gt;#&lt;/a&gt; 从上到下一级一级查找，找到后再从下往上一级一级存&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;CPU 运行时，需要的操作数大部分来自寄存器&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;需从 (向) 存储器中取 (存) 数时，先访问 cache；若在，取自 cache&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;若不在 cache，则访问 RAM；若在，则取自 RAM (还会保存到 cache 上)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;若不在 RAM，则访问磁盘，操作数从磁盘中读出→RAM →cache&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;按存储器中信息的可保存性分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按存储器中信息的可保存性分类&#34;&gt;#&lt;/a&gt; 按存储器中信息的可保存性分类&lt;/h1&gt;
&lt;h2 id=&#34;断电后是否丢失数据&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#断电后是否丢失数据&#34;&gt;#&lt;/a&gt; 断电后是否丢失数据&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;挥发性存储器 (易失性存储器)&lt;br /&gt;
 特点：断电后，信息即丢失&lt;br /&gt;
 SRAM、DRAM&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;非挥发性存储器 (非易失性 / 永久性存储器)&lt;br /&gt;
 特点：断电后，信息不丢失&lt;br /&gt;
 ROM、磁盘、闪存&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;读出后是否保持数据&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#读出后是否保持数据&#34;&gt;#&lt;/a&gt; 读出后是否保持数据&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;破坏性存储器&lt;br /&gt;
特点：读出时原存信息被破坏，需重写&lt;br /&gt;
 DRAM&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;非破坏性存储器&lt;br /&gt;
特点：读出时，原存信息不被破坏&lt;br /&gt;
 SRAM&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;存储器技术指标&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储器技术指标&#34;&gt;#&lt;/a&gt; 存储器技术指标&lt;/h1&gt;
&lt;h2 id=&#34;存取时间ta-与-存储周期ts&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存取时间ta-与-存储周期ts&#34;&gt;#&lt;/a&gt; 存取时间 TA 与 存储周期 TS&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;存取时间 TA：启动一次存储器操作到完成该操作所用时间&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;读：从启动读命令到读出的数据送 MDR 所需的时间&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;写：从启动到将 MDR 内容写入指定存储单元的时间&lt;br /&gt;
亦称访问时间，是反映存储器速度的指标，决定了 CPU 发出读 / 写命令后必须等待的时间&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;存储周期 TS：亦称存取周期或访问周期&lt;br /&gt;
两连续两次启动同一存储器进行存取操作所需的最小时间间隔次启动包括：两次读，两次写，一次读或一次写&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;TA&amp;lt;TS ：&lt;br /&gt;
TA、TS 的差别依赖于存储信息的器件和电路，存储介质和控制线路需要恢复时间&lt;br /&gt;
破坏性读出须重写；非破坏性读出不须重写&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;存取宽度-与-存储带宽&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存取宽度-与-存储带宽&#34;&gt;#&lt;/a&gt; 存取宽度 与 存储带宽&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;存取宽度：一次访存操作可存取的数据位数或字节数 (银河 - I 的存取宽度是 64 位)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;存储带宽：每秒传输的最大数据量 (位 / 秒)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;mtbfmean-time-between-failure&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mtbfmean-time-between-failure&#34;&gt;#&lt;/a&gt; MTBF(Mean Time Between Failure)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;MTBF 表示两次故障之间的平均时间间隔&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;采用纠错编码技术进行容错处理&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;主存和cpu之间的两种通信方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主存和cpu之间的两种通信方式&#34;&gt;#&lt;/a&gt; 主存和 CPU 之间的两种通信方式&lt;/h1&gt;
&lt;h2 id=&#34;异步方式过程需握手信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#异步方式过程需握手信号&#34;&gt;#&lt;/a&gt; 异步方式过程 (需握手信号)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;读操作&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 送地址到地址线，主存进行地址译码&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 发读命令，然后等待存储器发回 “完成” 信号&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;主存收到读命令后开始读数，完成后发 “完成” 信号给 CPU&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 接收到 “完成” 信号，从数据线取数&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;同步方式的特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#同步方式的特点&#34;&gt;#&lt;/a&gt; 同步方式的特点&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;CPU 和主存由统一时钟信号控制，无需应答信号&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;主存总是在确定的时间内准备好数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 送出地址和读命令后，总是在确定的时间取数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;存储器芯片必须支持同步方式&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;主存和cpu的连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主存和cpu的连接&#34;&gt;#&lt;/a&gt; 主存和 CPU 的连接&lt;/h1&gt;
&lt;h2 id=&#34;-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#-2&#34;&gt;#&lt;/a&gt; &lt;/h2&gt;
&lt;h2 id=&#34;地址线的连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#地址线的连接&#34;&gt;#&lt;/a&gt; 地址线的连接&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;CPU 地址线数决定了整个主存空间的寻址范围&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 地址线数 &amp;gt; 存储芯片地址引脚线&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通常将 CPU 地址线的低位和存储芯片地址线相连，高位用作字扩展时的片选信号的译码&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;数据线的连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据线的连接&#34;&gt;#&lt;/a&gt; 数据线的连接&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;CPU 数据线数决定了一次可读写的最大数据宽度&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CPU 数据线数 &amp;gt; 存储芯片数据引脚线&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;通常将 CPU 数据线连到多个位扩展的芯片中，使扩展后的位数与 CPU 数据线数相等&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;控制线的连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#控制线的连接&#34;&gt;#&lt;/a&gt; 控制线的连接&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;若 CPU 读 / 写命令线和存储芯片的读 / 写控制线是一根，且电平信号一致，则可直接相连&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;若 CPU 读 / 写命令线分开，则需分别进行连接&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;ROM read only 不需要连接写使能 WR&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;按在计算机中的作用分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按在计算机中的作用分类&#34;&gt;#&lt;/a&gt; 按在计算机中的作用分类&lt;/h1&gt;
&lt;h2 id=&#34;寄存器型存储器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#寄存器型存储器&#34;&gt;#&lt;/a&gt; 寄存器型存储器&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;亦称便笺式存储器，由寄存器构成，封装在 CPU 内&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用于存放当前正在执行的指令和使用的数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用触发器实现，速度快，容量小 O (KB)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;高速缓冲存储器cache&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#高速缓冲存储器cache&#34;&gt;#&lt;/a&gt; 高速缓冲存储器 (Cache)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;位于 CPU 内部或位于主存和 CPU 之间&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用来存放当前正在执行的局部程序段和数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用 SRAM 实现，速度 O (ns)、容量 O (MB)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;主存储器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主存储器&#34;&gt;#&lt;/a&gt; 主存储器&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;位于 CPU 之外&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用来存放已被启动的程序及所用数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用 DRAM 实现，速度 O (ns)、容量 O (GB)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;辅助存储器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#辅助存储器&#34;&gt;#&lt;/a&gt; 辅助存储器&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;不能由 CPU 的指令直接访问&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用来存放暂不运行的程序、数据或存档文件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用磁、光等存储器件实现，容量大，但速度慢 O (ms)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;其它功能的存储器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#其它功能的存储器&#34;&gt;#&lt;/a&gt; 其它功能的存储器&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;控存 CM：存储微程序代码&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;表格存储器：为加快 CPU 处理而设置 (倒数表、函数表)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;字库和数据缓冲存储器：显示和印刷输出设备中&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;按存储介质分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按存储介质分类&#34;&gt;#&lt;/a&gt; 按存储介质分类&lt;/h1&gt;
&lt;h2 id=&#34;半导体存储器scm&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#半导体存储器scm&#34;&gt;#&lt;/a&gt; 半导体存储器 (SCM)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;速度快，用作内存&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;记忆原理：双稳态触发器、电容 (静态、动态)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;磁表面存储器msm&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#磁表面存储器msm&#34;&gt;#&lt;/a&gt; 磁表面存储器 MSM&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;用陶瓷、非磁性金属或塑料作载磁体，磁化后具有两种不同的剩磁状态记录信息 “1” 和 “0”&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;非易失，容量大并且每位价格低 。用作外存&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;光盘存储器odm&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#光盘存储器odm&#34;&gt;#&lt;/a&gt; 光盘存储器 ODM&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;有机玻璃作载磁体，利用磁化、晶态 / 非晶态表示信息&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;非易失，可靠性高，保存时间长，容量大且易于更换&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;存储速度比硬盘低一个数量级&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;铁电存储器femfram-相变存储器pcm-阻变存储器reram&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#铁电存储器femfram-相变存储器pcm-阻变存储器reram&#34;&gt;#&lt;/a&gt; 铁电存储器 FeM (FRAM)、相变存储器 PCM、阻变存储器 ReRAM、……&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;掉电数据不丢失 (non-volatile)，速度快&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;按存储方式分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按存储方式分类&#34;&gt;#&lt;/a&gt; 按存储方式分类&lt;/h1&gt;
&lt;h2 id=&#34;随机访问存储器ram&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#随机访问存储器ram&#34;&gt;#&lt;/a&gt; 随机访问存储器 (RAM)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;存储器任意单元可随时访问且访问所需时间基本相同&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;访问时间与存储单元所处的物理位置无关&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;速度快 (ns)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;主存和 Cache&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;只读存储器romread-only-memory&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#只读存储器romread-only-memory&#34;&gt;#&lt;/a&gt; 只读存储器 (ROM)(Read Only Memory)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;只读是指正常工作时只读，能随机读出，不能随机写入&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;MROM：只能读，不能修改&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;PROM：只能修改一次，修改后只读&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;可多次改写 ROM：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;光擦除电可编程只读存储器，亦称 UV EPROM&lt;br /&gt;
——s 级别&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;电擦除电可编程只读存储器 E2PROM&lt;br /&gt;
——s 级别&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;块擦除电可编程的快擦写存储器 Flash Memory&lt;br /&gt;
——ms 级别（闪存）&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;顺序存储器sassequential-access-memory&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#顺序存储器sassequential-access-memory&#34;&gt;#&lt;/a&gt; 顺序存储器 (SAS)(Sequential Access Memory)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;存储时以数据块为单位存储，顺序地记录在存储介质上&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数据按顺序从存储载体的始端读出或写入，存取时间的长短与数据所在位置有关&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;速度慢、容量大、成本低，用作后援外存&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;磁带-电荷耦合器件ccd-vcd&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#磁带-电荷耦合器件ccd-vcd&#34;&gt;#&lt;/a&gt; 磁带、电荷耦合器件 CCD、VCD&lt;/h2&gt;
&lt;h1 id=&#34;常用半导体存储器常考&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常用半导体存储器常考&#34;&gt;#&lt;/a&gt; 常用半导体存储器（常考）&lt;/h1&gt;
&lt;h2 id=&#34;随机存取存储器ram&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#随机存取存储器ram&#34;&gt;#&lt;/a&gt; 随机存取存储器 (RAM)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;SRAM 静态随机存取存储器 (—— 用作 Cache)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;只要加上电源，信息就能一直保持&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对电气干扰相对不很敏感&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;比 DRAM 更快，也更贵&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;六管静态 MOS 管电路&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;SRAM 数据保存在一对正负反馈门电路中，只要供电，数据就一直保持，不是破环性读出，也不需要重写数据来保持数据不变。即：无需刷新！&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;DRAM 动态随机存取存储器 (—— 用作主存储器)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;每隔一段时间必须刷新一次&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对电气干扰比较敏感&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;比 SRAM 慢，但便宜&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;DRAM 读比写稍微快一点，因为读需要等行列地址就绪？&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;动态单管 MOS 电路&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;优点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;电路元件少&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;工作功耗小&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;集成度高，广泛用于大容量主存储器中&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;缺点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;速度慢&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;破坏性读出 (读后状态改变，需重写)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;需要定时刷新&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;随机存储器的地址译码&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;线选法 (一维地址译码) 存储矩阵&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;位片式 (二维双译码) 存储矩阵&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;地址引脚复用&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;RAS 有效时送行地址&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;CAS 有效时送列地址&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;只读存储器rom&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#只读存储器rom&#34;&gt;#&lt;/a&gt; 只读存储器 (ROM)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;不可在线改写内容的 ROM (—— 用作 BIOS)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;闪存 (Flash Memory)(——U 盘、SSD 等)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;划分为主存空间包rom和ram区&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#划分为主存空间包rom和ram区&#34;&gt;#&lt;/a&gt; 划分为主存空间包 ROM 和 RAM 区&lt;/h1&gt;
&lt;h2 id=&#34;rom区用来存放系统程序-标准子程序等选-rom-芯片构造&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rom区用来存放系统程序-标准子程序等选-rom-芯片构造&#34;&gt;#&lt;/a&gt; ROM 区用来存放系统程序、标准子程序等，选 ROM 芯片构造&lt;/h2&gt;
&lt;h2 id=&#34;ram区用来存放用户程序选-ram-芯片构造&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ram区用来存放用户程序选-ram-芯片构造&#34;&gt;#&lt;/a&gt; RAM 区用来存放用户程序，选 RAM 芯片构造&lt;/h2&gt;
&lt;h1 id=&#34;存储容量的扩展&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储容量的扩展&#34;&gt;#&lt;/a&gt; 存储容量的扩展&lt;/h1&gt;
&lt;p&gt;默认使用同一种芯片扩展&lt;/p&gt;
&lt;h2 id=&#34;位扩展&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#位扩展&#34;&gt;#&lt;/a&gt; 位扩展&lt;/h2&gt;
&lt;p&gt;存储芯片 (mk×n 位 / 片) 构成存储器 (mk×N 位)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;字数不变 (存储单元个数不变)，位数扩展 (字长加长)&lt;br /&gt;
 芯片地址码位数 = 存储器的地址码位数&lt;br /&gt;
芯片存储单元中所含位元数 &amp;lt; 存储器存储单元中所含位元数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;给出地址后，该存储单元中所有芯片同时工作&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;所有芯片地址范围相同&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;需存储芯片数：ceil (N /n) 片&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;字扩展&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字扩展&#34;&gt;#&lt;/a&gt; 字扩展&lt;/h2&gt;
&lt;p&gt;存储芯片 (mk×n 位 / 片) 构成存储器 (Mk×n 位)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;位数不变 (字长不变)、扩充容量 (存储单元个数增加)&lt;br /&gt;
 芯片地址码位数 &amp;lt; 存储器的地址码位数&lt;br /&gt;
芯片存储单元中所含位元数 = 存储器存储单元中所含位元数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;给出地址后，选中芯片工作&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;每个芯片地址范围不同&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;需存储芯片数：ceil (M /m) 片&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;片选 依据 增加的高位地址码&lt;br /&gt;
增加的高位地址码 = 存储器地址码位数 - 每片芯片的地址码位数&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;字位同时扩展&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字位同时扩展&#34;&gt;#&lt;/a&gt; 字位同时扩展&lt;/h2&gt;
&lt;p&gt;存储芯片 (mk×n 位) 构成存储器 (Mk×N 位)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;存储单元个数，字长同时增加&lt;br /&gt;
芯片地址码位数 &amp;lt; 存储器的地址码位数&lt;br /&gt;
芯片存储单元中所含位元数 &amp;lt; 存储器存储单元中所含位元数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;给出地址后，同行芯片均工作&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;需存储芯片数： ceil (M /m) * ceil ( N /n ) 片&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;思维导图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#思维导图&#34;&gt;#&lt;/a&gt; 思维导图&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/principles-of-computer-composition/Cache.png&#34; alt=&#34;Cache&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;cache的结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache的结构&#34;&gt;#&lt;/a&gt; Cache 的结构&lt;/h1&gt;
&lt;h2 id=&#34;cache是小容量-高速缓冲存储器由sram组成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache是小容量-高速缓冲存储器由sram组成&#34;&gt;#&lt;/a&gt; Cache 是小容量、高速缓冲存储器，由 SRAM 组成&lt;/h2&gt;
&lt;h2 id=&#34;一般将cache和主存的存储空间都划分为若干大小相同的块并映射&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#一般将cache和主存的存储空间都划分为若干大小相同的块并映射&#34;&gt;#&lt;/a&gt; 一般将 Cache 和主存的存储空间都划分为若干大小相同的块并映射&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;把主存划分成大小相等的主存块 (Block)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Cache 中存放一个主存块的对应单位称为行 (line) 或槽 (Slot) 或项 (Entry) 或块 (Block)，一段 Cache 行包括：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Valid 位，1 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;LRU 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Dirty 位，1 位，采用 Write Back (写回、一次性写、回写) 时需要&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Tag 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Data 数据&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;主存块 (Block) 与 Cache 中的 行 / 槽 / 项 / 块 映射&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;cache中存放最近访问的数据&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache中存放最近访问的数据&#34;&gt;#&lt;/a&gt; Cache 中存放最近访问的数据&lt;/h2&gt;
&lt;h1 id=&#34;cache工作原理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache工作原理&#34;&gt;#&lt;/a&gt; Cache 工作原理&lt;/h1&gt;
&lt;h2 id=&#34;程序运行时cpu使用的一部分数据指令会预先成批拷贝到cache中cache的内容是主存储器中部分内容的映象副本&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#程序运行时cpu使用的一部分数据指令会预先成批拷贝到cache中cache的内容是主存储器中部分内容的映象副本&#34;&gt;#&lt;/a&gt; 程序运行时，CPU 使用的一部分数据 / 指令会预先成批拷贝到 Cache 中，Cache 的内容是主存储器中部分内容的映象 (副本)&lt;/h2&gt;
&lt;h2 id=&#34;当cpu需从主存读写数据或指令时先查看cache&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#当cpu需从主存读写数据或指令时先查看cache&#34;&gt;#&lt;/a&gt; 当 CPU 需从主存读 (写) 数据或指令时，先查看 Cache&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;失效或缺失 (miss)&lt;br /&gt;
 若被访问信息不在 cache 中，则直接从 Cache 中取，不用访问主存&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;命中 (hit)&lt;br /&gt;
 若被访问信息在 cache 中，则直接访问主存&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;cache对程序员编译器是透明的&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache对程序员编译器是透明的&#34;&gt;#&lt;/a&gt; Cache 对程序员 (编译器) 是透明的&lt;/h2&gt;
&lt;h2 id=&#34;对操作系统程序员也是基本透明的&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对操作系统程序员也是基本透明的&#34;&gt;#&lt;/a&gt; 对操作系统程序员也是基本透明的&lt;/h2&gt;
&lt;h2 id=&#34;对一些内核高级程序员不是透明的&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对一些内核高级程序员不是透明的&#34;&gt;#&lt;/a&gt; 对一些内核高级程序员不是透明的&lt;/h2&gt;
&lt;h1 id=&#34;程序访问局部性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#程序访问局部性&#34;&gt;#&lt;/a&gt; 程序访问局部性&lt;/h1&gt;
&lt;h2 id=&#34;时间局部性temporal-locality&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时间局部性temporal-locality&#34;&gt;#&lt;/a&gt; 时间局部性 (Temporal Locality) ：&lt;/h2&gt;
&lt;p&gt;刚被访问过的存储单元很可能不久又被访问&lt;br /&gt;
所以让最近被访问过的信息保留在靠近 CPU 的存储器中&lt;/p&gt;
&lt;h2 id=&#34;空间局部性-spatial-locality&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#空间局部性-spatial-locality&#34;&gt;#&lt;/a&gt; 空间局部性 (Spatial Locality) ：&lt;/h2&gt;
&lt;p&gt;刚被访问过的存储单元的邻近单元很可能不久被访问，单个数据不考虑空间局部性&lt;br /&gt;
所以将刚被访问过的存储单元的邻近单元调到靠近 CPU 的存储器中&lt;/p&gt;
&lt;h2 id=&#34;块大小的设置需利用空间局部性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#块大小的设置需利用空间局部性&#34;&gt;#&lt;/a&gt; 块大小的设置需利用空间局部性&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;块太小，无法利用空间局部性，发生缺失的概率增大&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;cache在计算机存储层次结构中的位置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache在计算机存储层次结构中的位置&#34;&gt;#&lt;/a&gt; Cache 在计算机存储层次结构中的位置&lt;/h1&gt;
&lt;h2 id=&#34;&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#&#34;&gt;#&lt;/a&gt; &lt;/h2&gt;
&lt;h2 id=&#34;cache位于cpu内速度几乎与cpu一样快&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache位于cpu内速度几乎与cpu一样快&#34;&gt;#&lt;/a&gt; Cache 位于 CPU 内，速度几乎与 CPU 一样快&lt;/h2&gt;
&lt;h2 id=&#34;块block是一个定长块是两层存储器之间存储信息的最小单元-cache是主存一部分的副本&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#块block是一个定长块是两层存储器之间存储信息的最小单元-cache是主存一部分的副本&#34;&gt;#&lt;/a&gt; 块 (Block) 是一个定长块，是两层存储器之间存储信息的最小单元。Cache 是主存一部分的副本&lt;/h2&gt;
&lt;h1 id=&#34;cache替换算法-淘汰策略问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache替换算法-淘汰策略问题&#34;&gt;#&lt;/a&gt; Cache 替换算法 / 淘汰策略问题&lt;/h1&gt;
&lt;h2 id=&#34;当一个新的主存块需要复制到cache中时如果cache中的对应行已经全部被占满如何选择被替换掉的cache行&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#当一个新的主存块需要复制到cache中时如果cache中的对应行已经全部被占满如何选择被替换掉的cache行&#34;&gt;#&lt;/a&gt; 当一个新的主存块需要复制到 Cache 中时，如果 Cache 中的对应行已经全部被占满，如何选择被替换掉的 Cache 行？&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;直接映射（Direct Mapped）Cache&lt;br /&gt;
 映射唯一，无条件用新信息替换老信息&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;N 路组相联（N-way Set Associative）Cache&lt;br /&gt;
 每个主存数据有 N 个 Cache 行可选择，需考虑替换哪一行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;全相联（Fully Associative）Cache&lt;br /&gt;
 每个主存数据可存放到 Cache 任意行中，需考虑替换哪一行&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;先进先出first-in-first-outfifo&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#先进先出first-in-first-outfifo&#34;&gt;#&lt;/a&gt; 先进先出（First In First Out，FIFO）&lt;/h2&gt;
&lt;p&gt;总是把最近最少用的那一块淘汰掉，利用时间局部性&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;加一位标记位标记当前哪一行是最先进入的&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;替换掉之后按顺序将下一行标记为最先进入的，最后一行被替换掉则标记第一行&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;最近最少用least-recently-usedlru&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最近最少用least-recently-usedlru&#34;&gt;#&lt;/a&gt; 最近最少用（Least Recently Used，LRU）&lt;/h2&gt;
&lt;p&gt;总是把最近最少用的那一块淘汰掉，利用时间局部性&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;具体实现：通过给每个 Cache 行设定一个计数器，根据计数值来记录这些主存块的使用情况。这个计数值称为 LRU 位。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;组相联每组 n 行时，LRU 位长度 = log_2 (n)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;全相联相当于组相联只有一组，LRU 位长度 = log_2 (Cache 的行数)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;命中时，被访问行的 LRU 位置 0，其他行 LRU 位加 1，其余不变&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;未命中且该组未满时，新行 LRU 位置为 0，其余全加 1&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;未命中且该组已满时，LRU 位最大的那一行中的主存块被淘汰，新行 LRU 位置为 0，其余加 1&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;LRU 位的最大值 = n-1 (从 0 开始计数)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;LRU 算法的命中率随组中行数的增大而提高&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;随机替换random&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#随机替换random&#34;&gt;#&lt;/a&gt; 随机替换（Random）&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;随机地从候选的槽中选取一个淘汰，与使用情况无关&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;模拟试验表明，随机替换算法在性能上只稍逊于 LRU 算法，而且代价低！&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;最不经常使用lfu&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最不经常使用lfu&#34;&gt;#&lt;/a&gt; 最不经常使用 LFU&lt;/h2&gt;
&lt;h1 id=&#34;相关指标与术语&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#相关指标与术语&#34;&gt;#&lt;/a&gt; 相关指标与术语&lt;/h1&gt;
&lt;h2 id=&#34;命中hit要访问的信息在cache中&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#命中hit要访问的信息在cache中&#34;&gt;#&lt;/a&gt; 命中（Hit）：要访问的信息在 Cache 中&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Hit Rate (命中率 p)： 在 Cache 中的概率&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Hit Time (命中时间 Tc) ：访问 Cache 所需时间，包括：判断时间 + Cache 访问&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;失效miss要访问的信息不在cache中&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#失效miss要访问的信息不在cache中&#34;&gt;#&lt;/a&gt; 失效（Miss）：要访问的信息不在 Cache 中&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Miss Rate (缺失率 / 失效率) = 1 - (Hit Rate) = 1-p&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Miss Penalty (失效损失 Tm)：从主存将一块数据读取到 Cache 所需时间，包括访问主存块，向上逐层传输块直至将数据块放入发生缺失的那一层所需时间。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;平均访问时间-p-tc-1-p-tm-tc-tc-1-p-tm&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#平均访问时间-p-tc-1-p-tm-tc-tc-1-p-tm&#34;&gt;#&lt;/a&gt; 平均访问时间 = p × Tc + (1-p) × (Tm + Tc) = Tc + (1-p) × Tm&lt;/h2&gt;
&lt;p&gt;【失效损失 Tm】 不包括 【命中时间 Tc】！&lt;em&gt;考点&lt;/em&gt;&lt;/p&gt;
&lt;h2 id=&#34;cache抖动&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache抖动&#34;&gt;#&lt;/a&gt; Cache 抖动&lt;/h2&gt;
&lt;p&gt;由于内存中不同主存块都映射到 Cache 同一行，某些块在主存和 Cache 之间频繁传送，产生了频繁的 Cache 替换，称之为 Cache 抖动&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;可能引起 Cache 抖动的 Cache 失效类型&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;容量失效&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;冲突失效&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;增加容量和相联性，有助于缓解这种现象&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;逻辑地址&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑地址&#34;&gt;#&lt;/a&gt; 逻辑地址&lt;/h2&gt;
&lt;p&gt;CPU 给出的虚拟地址&lt;/p&gt;
&lt;h2 id=&#34;物理地址-主存地址&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#物理地址-主存地址&#34;&gt;#&lt;/a&gt; 物理地址 / 主存地址&lt;/h2&gt;
&lt;p&gt;在 Cache 和主存中查询所用的地址&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Tag 位，与 Cache 中的 Tag 位比较，相等则命中&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Index 位，组号位，只有组相联才有&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Offset 位，在 Cache 行或主存块中的偏移量，即最低位块内地址&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;关联度&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关联度&#34;&gt;#&lt;/a&gt; 关联度&lt;/h2&gt;
&lt;p&gt;主存块映射到 Cache 时，可能存放的位置个数&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;关联度最低？直接映射（关联度为 1）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;关联度居中？N - 路组相联映射（关联度为 N）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;关联度最高？全相联映射（为 Cache 行数）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Cache 大小和块大小一定的情况下直观结论&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;提高关联度通常能够降低缺失率 (miss rate)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;提高关联度通常会增加命中时间&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;cache的失效率miss-rate&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache的失效率miss-rate&#34;&gt;#&lt;/a&gt; Cache 的失效率（Miss Rate）&lt;/h1&gt;
&lt;h2 id=&#34;miss-rate与cache大小-block大小-映射方式-cache级数等有关&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#miss-rate与cache大小-block大小-映射方式-cache级数等有关&#34;&gt;#&lt;/a&gt; Miss Rate 与 Cache 大小、Block 大小、映射方式、Cache 级数等有关&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Cache 大小：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Cache 越大，Miss Rate 越低&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;但成本越高！&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Block 大小：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Block 越大，Miss Rate 越低，因为空间局部性充分发掘&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Block 大小在 Cache 大小中所占的比例增加到一定程度时， Miss Rate 也会随之增加&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Cache 不扩大时 Cache Block 的总数变少了，冲突变大&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Cache 映射方式&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Cache 容量小时， Cache 映射方式对 Miss Rate 有影响&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Cache 容量大时，Cache 映射方式对 Miss Rate 影响不大&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;映射到同一组的概率降低&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;cache失效类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache失效类型&#34;&gt;#&lt;/a&gt; Cache 失效类型&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;强制失效 (Compulsory misses)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;首次访问某数据块时，必然引起的 Cache 失效&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;增加 Block 大小，有利于减少此类不命中&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;容量失效 (Capacity misses)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Cache 不能存放程序运行所需的所有块，替换后再次被使用所引起的 Cache 失效&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;增加 Cache 大小，有利于减少此类不命中&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;冲突失效 (Conflict misses)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;映射到同一组的数据块个数超过组内可容纳的块时，竞争所引起的 Cache 失效&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;全相联没有此类失效，但价格贵且访问速度慢&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;cache的一致性问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache的一致性问题&#34;&gt;#&lt;/a&gt; Cache 的一致性问题&lt;/h1&gt;
&lt;h2 id=&#34;导致cache和主存数据不一致的情况&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#导致cache和主存数据不一致的情况&#34;&gt;#&lt;/a&gt; 导致 Cache 和主存数据不一致的情况&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;情况 1：当 Cache 中的内容进行更新时，而没有改变主存中的相应内容时，Cache 和主存之间产生了不一致 (inconsistent)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;情况 2：当多个设备都允许访问主存时&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;例：I/O 设备可通过 DMA 方式直接读写内存时，如果 Cache 中的内容被修改，则 I/O 设备读出的对应主存单元的内容无效；若 I/O 设备修改了主存单元的内容，则对应 Cache 行中的内容无效。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;情况 3：当多个 CPU 都有各自私有的 Cache 并且共享主存时&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;例：某个 CPU 修改了自身 Cache 中的内容，则对应的主存单元和其他 CPU 中对应的 Cache 行的内容都要变为无效。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;cache写机制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache写机制&#34;&gt;#&lt;/a&gt; Cache 写机制&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;写命中 (Write Hit)&lt;br /&gt;
 要写的单元已经在 Cache 中时&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Write Through (写直达、写通过、直写、写穿透)&lt;br /&gt;
 当一个写操作产生时，无论写的是 Cache 还是主存，新值同时写到 Cache 和主存的块中&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;问题：内存速度太慢，所以会导致 CPU “被拖累”，CPU 性能降低&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;一种改进措施：在 Cache 和主存之间使用写缓冲 (Write Buffer)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;当一个数据等待被写入主存时，先将其存入写缓冲；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;在把数据写入 Cache 和写缓冲后，处理器继续执行命令；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;当写主存操作结束后，写缓冲里的数据释放&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;写穿透 / 直达 Cache 可用写分配或写不分配&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Write Back (写回、一次性写、回写)&lt;br /&gt;
 当一个写操作产生时，新值仅被写到 Cache 中，而不被写入主存&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;大大降低主存带宽需求&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;提高系统性能&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;控制可能很复杂&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;每个 Cache 行都设置一个修改位 (“dirty bit - 脏位”)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;如果修改位为 “0”，则说明对应主存块没有被修改过&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果对应 Cache 行中的主存块被修改，就同时置修改位为 “1”&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;只有当修改位为 “1” 的块从 cache 中替换出去时，才把它写回主存&lt;br /&gt;
（写不命中时 Cache 里没有有效的对应块，即使写分配也不需要考虑 Cache 中的数据。但是写分配写入 Cache 新的行时，被替换掉的行不能忘了考虑写回）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;修改位为 “0” 的块从 cache 中替换出去时，不写回主存&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;写回 Cache 通常用写分配&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;写不命中 (Write Miss)&lt;br /&gt;
 要写的单元不在 Cache 中时&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Allocate-on-miss (写分配)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;更新主存块中相应单元，再将该主存块装入 Cache；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;试图利用空间局部性，但增加了从主存读入一个块的开销&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;No-allocate-on-write (写不分配)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;直接写主存，不把被写数据放入 Cache，同时将 Cache 中该行 Valid 位置 0；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;减少了从主存读一个块的开销，但没有利用空间局部性&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;cache和主存之间的映射&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cache和主存之间的映射&#34;&gt;#&lt;/a&gt; Cache 和主存之间的映射&lt;/h1&gt;
&lt;h2 id=&#34;直接映射-模映射-direct-mapped&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#直接映射-模映射-direct-mapped&#34;&gt;#&lt;/a&gt; 直接映射 / 模映射 （Direct Mapped）&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;原理：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;把主存的每一块映射到一个固定的 Cache 行中。&lt;br /&gt;
Cache 总行数为 N，将存储空间总块数为 M 的主存分成 K = M/N 个组群，每个组群有 N 个块；&lt;br /&gt;
即每个主存地址对应于高速缓存中唯一的地址，也称模映射（本质是哈希）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;映射关系为：Cache 行号 = 主存块号 mod Cache 行数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;物理地址&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Tag 位，标记位&lt;br /&gt;
长度 = log _2 (主存中 块 的 数量 / Cache 中 块 的 数量) =log_2 (K)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Index 位，Cache 槽号&lt;br /&gt;
长度 = log _2 (Cache 中 块 的 数量) = Log_2 (N)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Offset 位，块内地址&lt;br /&gt;
长度 = log _2 (块 的 大小) (按编址单位算)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;关联度 = 1&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;易实现 (求低地址就行了) 电路简单，命中时间短&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;淘汰 / 替换策略简单&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不灵活，Cache 存储空间得不到充分利用，命中率低，抖动多&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;全相联映射fully-associative&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#全相联映射fully-associative&#34;&gt;#&lt;/a&gt; 全相联映射（Fully Associative）&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;原理：&lt;br /&gt;
主存块可装到 Cache 任一行 / 槽中，称为全相联映射&lt;br /&gt;
 Cache 有几个 slot 就最多需要查找多少次 slot，查找时需要一个 slot 一个 slot 比较 Tag 位查找（除非并行同时比较所有 Cache 行的 Tag，硬件实现更复杂）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;物理地址&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Tag 位，标记位&lt;br /&gt;
长度 = log _2 (主存中 块 的 数量)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Offset 位，块内地址&lt;br /&gt;
长度 = log _2 (块 的 大小) (按编址单位算)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;关联度 = Cache 的行的数量&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;块冲突概率低：只要有空闲 Cache 块，都不会发生冲突&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;实现复杂 (比较逻辑的硬件代价大)、速度慢&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;组相联映射n-way-set-associative&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#组相联映射n-way-set-associative&#34;&gt;#&lt;/a&gt; 组相联映射（N-way Set Associative）&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;n - 路组相联将总行数为 N 的 Cache 分成 S = N/n 组，每一组有 n 行；&lt;br /&gt;
将存储空间总块数为 M 的主存分成 K = M/S = M*n/N 个组群，每个组群有 S 个块；&lt;br /&gt;
把主存块映射到 Cache 固定组的任一行中。即：组间模映射、组内全映射&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;物理地址&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Tag 位，标记位&lt;br /&gt;
长度 = log _2 (主存中 块 的 数量 / 组的数量) = log _2 (K)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;组号位&lt;br /&gt;
长度 = log _2 (组 的 数量) = log _2 (S)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Offset 位，块内地址&lt;br /&gt;
长度 = log _2 (块 的 大小) (按编址单位算)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;关联度 = n&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;结合直接映射和全相联映射的优点。当 Cache 的组数为 1 时，则为全相联映射；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;每组两个行（2 路组相联）较常用。在较大容量的 L2 Cahce 和 L3 Cahce 中使用 4 路以上&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;当每组只有一行时，则为直接映射&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;当只有一组时，则为全相联映射&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;思维导图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#思维导图&#34;&gt;#&lt;/a&gt; 思维导图&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/principles-of-computer-composition/%E6%95%B0%E6%8D%AE%E9%80%9A%E8%B7%AF.png&#34; alt=&#34;数据通路&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;cpu-processor&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cpu-processor&#34;&gt;#&lt;/a&gt; CPU (Processor)&lt;/h1&gt;
&lt;h2 id=&#34;control-控制器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#control-控制器&#34;&gt;#&lt;/a&gt; Control 控制器&lt;/h2&gt;
&lt;p&gt;指令执行过程中，数据所经过的路径 (包括路径中的部件)—— 指令的执行部件&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;控制器的基本功能&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;取指令 (控制指令流出 — PC)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;分析指令 (控制指令分析 — IR)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;执行指令，发出各种操作命令&lt;br /&gt;
 (控制指令执行 — REGs 和 ALU)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;确定下一条指令的地址&lt;br /&gt;
 (控制指令流向 —PC)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;执行环境的建立与保护 (控制执行环境的维护 —FLAGs/PSW)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;datapath-数据通路&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#datapath-数据通路&#34;&gt;#&lt;/a&gt; Datapath 数据通路&lt;/h2&gt;
&lt;p&gt;对指令进行译码，生成指令对应的控制信号，控制数据通路的动作，能对指令的执行部件发出控制信号 —— 指令的控制部件&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;数据通路的构成&lt;br /&gt;
由 “操作元件” 和 “存储元件” 通过总线或分散方式连接而成&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数据通路的功能&lt;br /&gt;
进行数据存储、处理、传送&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;数据通路由两类部件组成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据通路由两类部件组成&#34;&gt;#&lt;/a&gt; 数据通路由两类部件组成&lt;/h1&gt;
&lt;h2 id=&#34;组合逻辑元件-or-操作元件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#组合逻辑元件-or-操作元件&#34;&gt;#&lt;/a&gt; 组合逻辑元件 or 操作元件&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;组合逻辑元件的特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;其输出只取决于当前的输入&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;所有输入到达后，经过一定的逻辑门延时，输出端改变，并保持到下次改变，不需要时钟信号来定时&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;包括：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;译码器 (Decoder)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;多路选择器 (MUX)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;加法器 (Adder)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;算术逻辑部件 (ALU)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;存储元件-or-状态元件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储元件-or-状态元件&#34;&gt;#&lt;/a&gt; 存储元件 or 状态元件&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;状态 (存储) 元件的特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;具有存储功能，在时钟控制下输入状态被写到电路中，直到下一个时钟到达&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;输入端状态由时钟决定何时写入，输出端状态随时可读出&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;定时方式：规定信号何时写入状态元件或何时从状态元件读出&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;边沿触发 (edge-triggered) 方式：状态单元中的值只在时钟边沿改变。每个时钟周期改变一次&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;上升沿 (rising edge) 触发：在时钟正跳变时进行读 / 写&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;下降沿 (falling edge) 触发：在时钟负跳变时进行读 / 写&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;包括&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;寄存器 (组)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;寄存器 (Register)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;写使能 (Write Enable-WE) 信号&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;0: 时钟边沿到时，输出不变&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;1: 时钟边沿到时，输出开始变为输入&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;若每个时钟边沿都写入，则不需 WE 信号&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;寄存器组 (Register File)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;两个读口 (组合逻辑操作)：busA 和 busB&lt;br /&gt;
 不需要 “读使能”&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;分别由 RA 和 RB 给出地址。地址 RA 或 RB 有效后，经一个 “取数时间 (AccessTime)”，busA 和 busB 有效&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;一个写口 (时序逻辑操作)：写使能&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;为 1 且时钟边沿到时，busW 传来的值开始被写入 RW 指定的寄存器中&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;存储器（理想存储器）&lt;br /&gt;
按存储内容分为：指令存储器 和 数据存储器&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Data Out：32/64 位读出数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Data In：   32/64 位写入数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Address：读写共用一个 32/64 位地址&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;读 (组合逻辑操作)：地址 Address 有效后，经一个 “取数时间 (AccessTime)”，Data Out 上数据有效&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;写 (时序逻辑操作)：写使能为 1 且时钟 Clk 边沿到来，Data In 传来的值开始被写入 Address 指定的存储单元&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;元件之间的连接方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#元件之间的连接方式&#34;&gt;#&lt;/a&gt; 元件之间的连接方式&lt;/h1&gt;
&lt;h2 id=&#34;总线式连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总线式连接&#34;&gt;#&lt;/a&gt; 总线式连接&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;单总线数据通路&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;三总线数据通路&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;总线 A、B 分别传送两个源操作数，&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;总线 C 传送结果&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;采用双口寄存器&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;分散式连接&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分散式连接&#34;&gt;#&lt;/a&gt; 分散式连接&lt;/h2&gt;
&lt;h2 id=&#34;早期累加器型指令数据通路&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#早期累加器型指令数据通路&#34;&gt;#&lt;/a&gt; 早期累加器型指令数据通路&lt;/h2&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;
